func (s *Store) History(artifactID, definitionID string) ([]RunRecord, error) {
	entries, err := s.loadRuns()
	if err != nil {
		return nil, err
	}
	filtered := make([]RunRecord, 0, len(entries))
	for _, rec := range entries {
		if artifactID != "" && !containsString(rec.ArtifactIDs, artifactID) {
			continue
		}
		if definitionID != "" && rec.DefinitionID != definitionID {
			continue
		}
		filtered = append(filtered, rec)
	}
	return filtered, nil
}

func (s *Store) Log(runID string) (string, string, error) {
	rec, err := s.loadRunByID(runID)
	if err != nil {
		return "", "", err
	}
	return rec.Result.Stdout, rec.Result.Stderr, nil
}

func (s *Store) Result(runID string) (RunResult, error) {
	rec, err := s.loadRunByID(runID)
	if err != nil {
		return RunResult{}, err
	}
	return rec.Result, nil
}

func (s *Store) SaveDefinition(def Definition) error {
	if def.ID == "" {
		return fmt.Errorf("id is required")
	}
	if len(def.ArtifactIDs) == 0 {
		return fmt.Errorf("artifact_ids is required")
	}
	return s.saveDefinitionBead(def)
}

func (s *Store) readRunBundle(dir string) (RunRecord, error) {
	manifestRaw, err := os.ReadFile(filepath.Join(dir, "manifest.json"))
	if err != nil {
		return RunRecord{}, err
	}
	resultRaw, err := os.ReadFile(filepath.Join(dir, "result.json"))
	if err != nil {
		return RunRecord{}, err
	}
	var manifest RunManifest
	if err := json.Unmarshal(manifestRaw, &manifest); err != nil {
		return RunRecord{}, err
	}
	var result RunResult
	if err := json.Unmarshal(resultRaw, &result); err != nil {
		return RunRecord{}, err
	}
	return RunRecord{RunManifest: manifest, Result: result}, nil
}

func syncPath(path string) error {
	f, err := os.Open(path)
	if err != nil {
		return err
	}
	defer f.Close()
	return f.Sync()
}

func provenance() Provenance {
	host, _ := os.Hostname()
	return Provenance{Host: host}
}

func containsString(values []string, target string) bool {
	for _, value := range values {
		if value == target {
			return true
		}
	}
	return false
}

func flattenEnv(values map[string]string) []string {
	out := make([]string, 0, len(values))
	for key, value := range values {
		out = append(out, fmt.Sprintf("%s=%s", key, value))
	}
	sort.Strings(out)
	return out
}

func captureCommand(cmd *osexec.Cmd) (string, string, error) {
	var stdoutBuf, stderrBuf strings.Builder
	cmd.Stdout = &stdoutBuf
	cmd.Stderr = &stderrBuf
	err := cmd.Run()
	return stdoutBuf.String(), stderrBuf.String(), err
}

var measurementPattern = regexp.MustCompile(`(?i)(-?\d+(?:\.\d+)?)(?:\s*)(ms|s|sec|seconds?)?`)

func normalizeMeasurement(stdout string) (float64, string) {
	trimmed := strings.TrimSpace(stdout)
	if trimmed == "" {
		return 0, ""
	}
	if value, unit, ok := parseJSONMeasurement(trimmed); ok {
		return value, unit
	}
	if value, unit, ok := parseTextMeasurement(trimmed); ok {
		return value, unit
	}
	return 0, ""
}

func parseJSONMeasurement(text string) (float64, string, bool) {
	var obj map[string]any
	if err := json.Unmarshal([]byte(text), &obj); err != nil {
		return 0, "", false
	}
	if raw, ok := obj["value"]; ok {
		switch v := raw.(type) {
		case float64:
			unit, _ := obj["unit"].(string)
			return v, unit, true
		case string:
			if parsed, err := strconv.ParseFloat(v, 64); err == nil {
				unit, _ := obj["unit"].(string)
				return parsed, unit, true
			}
		}
	}
	return 0, "", false
}

func parseTextMeasurement(text string) (float64, string, bool) {
	match := measurementPattern.FindStringSubmatch(text)
	if len(match) < 2 {
		return 0, "", false
	}
	value, err := strconv.ParseFloat(match[1], 64)
	if err != nil {
		return 0, "", false
	}
	unit := ""
	if len(match) >= 3 {
		unit = strings.ToLower(match[2])
	}
	return value, unit, true
}

func metricStatusForRun(status string) string {
	if status == StatusSuccess {
		return "pass"
	}
	return "fail"
}

func genAgentSessionID() string {
	b := make([]byte, 4)
	_, _ = rand.Read(b)
	return "as-" + hex.EncodeToString(b)
}

package exec

import (
	"context"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// AgentRunner is the interface exec needs from agent. SD-024 Stage 2:
// callers receive a sealed ResolvedConfig (durable knobs) and an
// AgentRunRuntime (per-invocation plumbing) instead of the legacy
// RunArgs struct.
type AgentRunner interface {
	Run(ctx context.Context, rcfg config.ResolvedConfig, runtime agent.AgentRunRuntime) (*agent.Result, error)
}

const (
	ExecutorKindCommand = "command"
	ExecutorKindAgent   = "agent"

	StatusSuccess  = "success"
	StatusFailed   = "failed"
	StatusTimedOut = "timed_out"
	StatusErrored  = "errored"
)

// Definition describes a machine-readable execution contract.
type Definition struct {
	ID          string       `json:"id"`
	ArtifactIDs []string     `json:"artifact_ids"`
	Executor    ExecutorSpec `json:"executor"`
	Result      ResultSpec   `json:"result,omitempty"`
	Evaluation  Evaluation   `json:"evaluation,omitempty"`
	Active      bool         `json:"active"`
	Required    bool         `json:"required,omitempty"`
	GraphSource bool         `json:"graph_source,omitempty"`
	CreatedAt   time.Time    `json:"created_at"`
}

// ExecutorSpec captures how a definition should be invoked.
type ExecutorSpec struct {
	Kind      string            `json:"kind"`
	Command   []string          `json:"command,omitempty"`
	Cwd       string            `json:"cwd,omitempty"`
	Env       map[string]string `json:"env,omitempty"`
	TimeoutMS int               `json:"timeout_ms,omitempty"`
}

// ResultSpec describes the structured result payload.
type ResultSpec struct {
	Metric *MetricResultSpec `json:"metric,omitempty"`
}

// MetricResultSpec defines the metric-shaped projection fields.
type MetricResultSpec struct {
	Unit        string `json:"unit,omitempty"`
	ValuePath   string `json:"value_path,omitempty"`
	SamplesPath string `json:"samples_path,omitempty"`
}

// Evaluation holds optional interpretation rules for a definition.
type Evaluation struct {
	Comparison string     `json:"comparison,omitempty"`
	Thresholds Thresholds `json:"thresholds,omitempty"`
}

// Thresholds captures the ratchet policy for metric-shaped results.
type Thresholds struct {
	WarnMS    float64 `json:"warn_ms,omitempty"`
	RatchetMS float64 `json:"ratchet_ms,omitempty"`
}

// RunManifest is the authoritative metadata record for one execution.
type RunManifest struct {
	RunID            string            `json:"run_id"`
	DefinitionID     string            `json:"definition_id"`
	ArtifactIDs      []string          `json:"artifact_ids"`
	ProducesArtifact string            `json:"produces_artifact,omitempty"`
	StartedAt        time.Time         `json:"started_at"`
	FinishedAt       time.Time         `json:"finished_at"`
	Status           string            `json:"status"`
	ExitCode         int               `json:"exit_code"`
	MergeBlocking    bool              `json:"merge_blocking,omitempty"`
	AgentSessionID   string            `json:"agent_session_id,omitempty"`
	Attachments      map[string]string `json:"attachments,omitempty"`
	Provenance       Provenance        `json:"provenance,omitempty"`
}

// Provenance captures host and version metadata for a run.
type Provenance struct {
	Actor      string `json:"actor,omitempty"`
	Host       string `json:"host,omitempty"`
	GitRev     string `json:"git_rev,omitempty"`
	DDXVersion string `json:"ddx_version,omitempty"`
}

// MetricObservation is the structured metric-shaped projection for a run.
type MetricObservation struct {
	ArtifactID   string           `json:"artifact_id"`
	DefinitionID string           `json:"definition_id"`
	ObservedAt   time.Time        `json:"observed_at"`
	Status       string           `json:"status"`
	Value        float64          `json:"value"`
	Unit         string           `json:"unit,omitempty"`
	Samples      []float64        `json:"samples,omitempty"`
	Comparison   ComparisonResult `json:"comparison,omitempty"`
}

// ComparisonResult records a comparison against a baseline or target.
type ComparisonResult struct {
	Baseline  float64 `json:"baseline"`
	Delta     float64 `json:"delta"`
	Direction string  `json:"direction"`
}

// RunResult stores the structured output for one execution run.
type RunResult struct {
	Metric *MetricObservation `json:"metric,omitempty"`
	Stdout string             `json:"stdout,omitempty"`
	Stderr string             `json:"stderr,omitempty"`
	Value  float64            `json:"value,omitempty"`
	Unit   string             `json:"unit,omitempty"`
	Parsed bool               `json:"parsed,omitempty"`
}

// RunRecord combines the manifest and structured result for CLI use.
type RunRecord struct {
	RunManifest
	Result RunResult `json:"result"`
}

// RunOptions carries call-site metadata that is not part of an execution
// definition. It lets wrappers such as `ddx artifact regenerate` annotate the
// immutable run without changing the reusable definition.
type RunOptions struct {
	ProducesArtifact string
}

